queries.sparql:
PREFIX : <http://ambrosia.example.org/airport#>
PREFIX p: <http://ambrosia.example.org/airport/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?o0 WHERE {
  {
    ?boeing a :Boeing .
    ?boeing p:Model ?model .
    BIND(?model AS ?o0)
  }
  UNION
  {
    ?airbus a :Airbus .
    ?airbus p:Model ?model .
    ?airbus p:Number_of_seats ?number_of_seats_f .
    FILTER((STR(?number_of_seats_f) = "180" || STR(?number_of_seats_f) = "180.0"))
    BIND(?model AS ?o0)
  }
}

